#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;int head[N],des[N],nxt[N],cgt,n,fa[N],sz[N];
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
inline void Solve()
{
	memset(head+1,0,(n=read())*sizeof(int));cgt=0;
	rep(2,n,i){int x=read(),y=read();x<y?ins(y,x):ins(x,y);}
	rep(1,n,i)sz[fa[i]=i]=1;int ans=0;
	rep(1,n,u)
	{
		int cnt=0;for(int i=head[u];i;i=nxt[i])
		{
			int v=fnd(des[i]);
			if(sz[v]>0)++cnt;sz[fa[v]=u]+=sz[v];
		}
		if(cnt>1){sz[u]-=3;++ans;}
	}
	printf("%d\n",ans);return;
}
int main()
{
	int T=read();while(T--)Solve();
	return 0;
}
